// fix-content-units-4-5-6.js
// Bug B fix: merges the duplicate/incomplete Chemistry & Physics Unit 4/5
// content into single correct WCH14/WCH15/WPH14/WPH15 entries, adds proper
// WCH13/WPH13 Practical Skills content (previously borrowed Unit 1's),
// removes the now-redundant chem3/chem4/phys3/phys4 entries, and fixes the
// Chemistry/Physics IAL picker from 9 buggy/duplicate buttons down to the
// correct 6 (Units 1-6), each pointing to the right content.
//
// Usage: place this file in your project root and run:
//   node fix-content-units-4-5-6.js

const fs = require('fs');
const path = require('path');

const filePath = path.join(__dirname, 'app', 'page.js');
let raw = fs.readFileSync(filePath, 'utf8');
const usesCRLF = raw.includes('\r\n');
let content = usesCRLF ? raw.replace(/\r\n/g, '\n') : raw;

function safeReplace(content, oldStr, newStr, label) {
  const occurrences = content.split(oldStr).length - 1;
  if (occurrences === 0) {
    throw new Error(`Could not find anchor for "${label}". It may already be patched, or the file changed. No changes made for this section.`);
  }
  if (occurrences > 1) {
    throw new Error(`Found ${occurrences} matches for "${label}", expected exactly 1. Refusing to patch ambiguously.`);
  }
  return content.replace(oldStr, newStr);
}

